+        }
+        if status == 429 {
+            return Err(TwitchError::RateLimited {
+                retry_after_ms: 30_000,
+            });
+        }
+
+        let text = resp.text().await.unwrap_or_default();
+        Err(TwitchError::Api {
+            status,
+            message: text,
+        })
